/// engine's conversation history when streaming completes.
///
/// ```swift
/// class MyHandler: StreamChunkListener {
/// func onChunk(chunk: StreamChunk) -> Bool {
/// print(chunk.delta, terminator: "")
/// return !chunk.done
/// }
/// }
