            pollFunc: ffi_onde_rust_future_poll_void,
            completeFunc: ffi_onde_rust_future_complete_void,
            freeFunc: ffi_onde_rust_future_free_void,
            liftFunc: { $0 },
            errorHandler: FfiConverterTypeInferenceError_lift
        )
}
